import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonArray;
import com.google.gson.JsonElement;
import org.junit.jupiter.api.Test;

public class JsonElementTest {

  @Test
  public void testGetAsJsonArray_WhenIsJsonArrayTrue_ReturnsThisAsJsonArray() {
    JsonElement element = mock(JsonElement.class);
    when(element.isJsonArray()).thenReturn(true);
    // Mock casting by making element a JsonArray mock as well
    JsonArray array = mock(JsonArray.class);
    // Use spy to combine behaviors
    JsonElement spyElement = spy(element);
    doReturn(true).when(spyElement).isJsonArray();
    // We need to return the spy as a JsonArray, so cast spy to JsonArray
    // Mockito doesn't allow casting mocks directly, so create a subclass for test
    JsonArray jsonArray = new JsonArray() {
      @Override
      public boolean isJsonArray() {
        return true;
      }
    };
    JsonElement jsonElement = spy(jsonArray);
    JsonArray result = jsonElement.getAsJsonArray();
    assertSame(jsonElement, result);
  }

  @Test
  public void testGetAsJsonArray_WhenIsJsonArrayFalse_ThrowsIllegalStateException() {
    JsonElement element = mock(JsonElement.class);
    when(element.isJsonArray()).thenReturn(false);
    // We need to call real method on mock but isJsonArray returns false
    // Use spy with real method call for getAsJsonArray
    JsonElement spyElement = spy(element);
    doReturn(false).when(spyElement).isJsonArray();
    IllegalStateException exception = assertThrows(IllegalStateException.class, spyElement::getAsJsonArray);
    assertTrue(exception.getMessage().startsWith("Not a JSON Array: "));
  }
}
